"""Interactive module pages for Marketplace, Deals and Save Food."""
from __future__ import annotations

import json


MODULES = {
    "market": {
        "eyebrow": "Balkan.Works Market",
        "title": "Pronađi lokalno. Objavi jasno.",
        "lead": "Poslovi, majstori, usluge i proizvodi u jednoj regionalnoj mreži.",
        "endpoint": "/api/market/listings",
        "form": """<select id=\"listing_type\"><option value=\"SERVICE\">Usluga</option><option value=\"CRAFTSMAN\">Majstor</option><option value=\"JOB\">Posao</option><option value=\"PRODUCT\">Proizvod</option><option value=\"BUSINESS\">Firma</option></select><input id=\"title\" placeholder=\"Naslov oglasa\"><textarea id=\"description\" placeholder=\"Šta nudite ili tražite?\"></textarea><div class=\"pair\"><input id=\"country_code\" value=\"RS\" maxlength=\"2\" placeholder=\"Država\"><input id=\"city_name\" placeholder=\"Grad\"></div><div class=\"pair\"><input id=\"price\" type=\"number\" min=\"0\" step=\"0.01\" placeholder=\"Cena (opciono)\"><input id=\"currency\" value=\"EUR\" maxlength=\"3\" placeholder=\"Valuta\"></div>""",
        "action": "Objavi oglas",
        "empty": "Još nema oglasa za izabranu lokaciju.",
    },
    "deals": {
        "eyebrow": "Balkan.works Deals",
        "title": "Akcije koje vredi videti.",
        "lead": "Digitalni flajeri i lokalne ponude direktno od verifikovanih firmi.",
        "endpoint": "/api/deals/offers",
        "form": """<select id=\"business_id\"><option value=\"\">Izaberi svoju firmu</option></select><input id=\"title\" placeholder=\"Naziv ponude\"><textarea id=\"description\" placeholder=\"Kratak opis akcije\"></textarea><div class=\"pair\"><input id=\"price\" type=\"number\" min=\"0.01\" step=\"0.01\" placeholder=\"Akcijska cena\"><input id=\"old_price\" type=\"number\" min=\"0.01\" step=\"0.01\" placeholder=\"Stara cena\"></div><div class=\"pair\"><input id=\"country_code\" value=\"RS\" maxlength=\"2\" placeholder=\"Država\"><input id=\"city_name\" placeholder=\"Grad\"></div><input id=\"valid_until\" type=\"datetime-local\" placeholder=\"Važi do\">""",
        "action": "Objavi ponudu",
        "empty": "Trenutno nema aktivnih ponuda za ovu lokaciju.",
    },
    "food": {
        "eyebrow": "Save Food",
        "title": "Dobra hrana ne mora da se baci.",
        "lead": "Rezerviši paket viška hrane iz lokalnih firmi i preuzmi ga u terminu koji ti odgovara.",
        "endpoint": "/api/food/packages",
        "form": """<select id=\"business_id\"><option value=\"\">Izaberi svoju firmu</option></select><input id=\"title\" placeholder=\"Naziv paketa\"><textarea id=\"description\" placeholder=\"Šta paket sadrži?\"></textarea><div class=\"pair\"><input id=\"quantity_available\" type=\"number\" min=\"1\" value=\"1\" placeholder=\"Količina\"><input id=\"price\" type=\"number\" min=\"0\" step=\"0.01\" placeholder=\"Cena\"></div><div class=\"pair\"><input id=\"pickup_from\" type=\"datetime-local\"><input id=\"pickup_until\" type=\"datetime-local\"></div>""",
        "action": "Objavi paket",
        "empty": "Trenutno nema paketa hrane u ponudi.",
    },
}


LOCATION_ENHANCEMENT = r'''<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"><style>#location-map{height:260px;border:1px solid #d9e3dc;border-radius:14px;margin:0 0 22px;background:#eaf1ed}.gps{background:#e5f5eb!important;color:#18704f!important;border:1px solid #bfe0c9!important}.location-note{font-size:12px;color:#62746e;align-self:center}</style>'''


LOCATION_SCRIPT = r'''<script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script><script>
(() => { const oldCountry=document.querySelector('#filter-country'), city=document.querySelector('#filter-city'), filter=document.querySelector('#filter'); if(!oldCountry||!city)return; const country=document.createElement('select');country.id='filter-country';country.value=oldCountry.value;oldCountry.replaceWith(country);city.setAttribute('list','regional-cities');const dataList=document.createElement('datalist');dataList.id='regional-cities';document.body.appendChild(dataList);const gps=document.createElement('button');gps.type='button';gps.className='gps';gps.textContent='⌖ Koristi moj GPS';filter.before(gps);const note=document.createElement('span');note.className='location-note';note.textContent='Izaberi lokaciju za lokalne rezultate';filter.after(note);const mapBox=document.createElement('div');mapBox.id='location-map';document.querySelector('.layout').before(mapBox);let map,marker,cities=[];function draw(lat,lon,label){if(!window.L)return;if(!map){map=L.map('location-map').setView([44.2,20.8],6);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:19,attribution:'© OpenStreetMap contributors'}).addTo(map)}map.setView([lat,lon],12);if(marker)marker.remove();marker=L.marker([lat,lon]).addTo(map).bindPopup(label).openPopup()}function sync(cityItem){if(!cityItem)return;city.value=cityItem.name;country.value=cityItem.country_code;const formCountry=document.querySelector('#country_code'),formCity=document.querySelector('#city_name');if(formCountry)formCountry.value=cityItem.country_code;if(formCity)formCity.value=cityItem.name;draw(cityItem.latitude,cityItem.longitude,cityItem.name)}async function loadCities(){try{cities=await fetch('/api/locations/cities?country_code='+encodeURIComponent(country.value)).then(r=>r.json());dataList.innerHTML=cities.map(x=>'<option value="'+x.name+'">').join('');const selected=cities.find(x=>x.name===city.value);if(selected)draw(selected.latitude,selected.longitude,selected.name)}catch(_){note.textContent='Lokacije se trenutno učitavaju.'}}fetch('/api/locations/countries').then(r=>r.json()).then(items=>{country.innerHTML=items.map(x=>'<option value="'+x.code+'">'+x.name+'</option>').join('');country.value='RS';loadCities()}).catch(()=>{country.innerHTML='<option value="RS">Srbija</option>'});country.onchange=()=>{city.value='';loadCities()};city.onchange=()=>sync(cities.find(x=>x.name.toLocaleLowerCase()===city.value.toLocaleLowerCase()));gps.onclick=()=>{if(!navigator.geolocation){note.textContent='Ovaj pregledač ne podržava GPS.';return}note.textContent='Tražimo tvoju lokaciju…';navigator.geolocation.getCurrentPosition(async position=>{const {latitude,longitude}=position.coords;draw(latitude,longitude,'Tvoja približna lokacija');try{const nearby=await fetch('/api/locations/nearby-cities?latitude='+latitude+'&longitude='+longitude+'&radius_km=250').then(r=>r.json());if(nearby.length){sync(nearby[0]);note.textContent='Pronađen najbliži grad: '+nearby[0].name;filter.click()}else note.textContent='Lokacija je postavljena; nema grada u regionalnom katalogu.'}catch(_){note.textContent='Lokacija je postavljena na mapi.'}},()=>{note.textContent='GPS dozvola nije odobrena.'},{enableHighAccuracy:true,timeout:10000,maximumAge:300000})};setTimeout(()=>draw(44.2,20.8,'Balkan.works'),300)} )();
</script>'''


def render_module_page(kind: str) -> str:
    config = MODULES[kind]
    template = '''<!doctype html><html lang="sr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>__TITLE__ · Balkan.works</title><style>
:root{--ink:#092c26;--pine:#0d4036;--paper:#fbfaf6;--orange:#ff6c37;--line:#d9e3dc;--muted:#62746e;--mint:#e5f5eb}*{box-sizing:border-box}body{margin:0;background:var(--paper);color:var(--ink);font-family:Inter,system-ui,sans-serif}.wrap{max-width:1140px;margin:auto;padding:0 24px}.nav{height:76px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid var(--line)}.brand{font-size:24px;font-weight:900;color:var(--ink);text-decoration:none}.brand i{color:var(--orange)}.nav a:last-child{font-size:14px;color:var(--pine);font-weight:800;text-decoration:none}.hero{padding:55px 0 32px;display:flex;justify-content:space-between;gap:30px;align-items:end}.eyebrow{color:var(--orange);font-weight:900;letter-spacing:1.4px;text-transform:uppercase;font-size:12px}h1{font:clamp(40px,6vw,66px)/.98 Georgia,serif;letter-spacing:-2.5px;margin:15px 0;max-width:720px}.lead{max-width:650px;color:var(--muted);font-size:17px;line-height:1.55}.filters{display:flex;gap:10px;flex-wrap:wrap;background:#fff;border:1px solid var(--line);border-radius:14px;padding:12px;margin:12px 0 26px}.filters input,.filters select,.composer input,.composer select,.composer textarea{font:inherit;border:1px solid var(--line);border-radius:8px;padding:11px;background:#fff;color:var(--ink)}.filters input{max-width:180px}.filters button,.composer button{background:var(--pine);border:0;border-radius:8px;padding:11px 14px;color:#fff;font-weight:800;cursor:pointer}.layout{display:grid;grid-template-columns:1.5fr .8fr;gap:22px;padding-bottom:60px}.list{display:grid;gap:12px}.item{background:#fff;border:1px solid var(--line);border-radius:14px;padding:18px}.item-top{display:flex;justify-content:space-between;gap:12px;align-items:start}.item h2{font-size:19px;margin:0 0 7px}.item p{color:var(--muted);line-height:1.5;margin:7px 0}.meta{font-size:13px;color:#587069}.price{color:var(--orange);font-weight:900;font-size:20px;white-space:nowrap}.old{font-size:12px;text-decoration:line-through;color:var(--muted);font-weight:500}.pill{background:var(--mint);color:#18704f;border-radius:99px;padding:5px 8px;font-size:11px;font-weight:800}.reserve{margin-top:10px;background:var(--orange)!important}.composer{background:#eaf5ee;border:1px solid #cde4d4;border-radius:14px;padding:18px;height:max-content}.composer h2{font:25px Georgia,serif;margin:0 0 4px}.composer p{color:var(--muted);font-size:13px;line-height:1.5}.composer input,.composer select,.composer textarea{display:block;width:100%;margin:8px 0}.composer textarea{min-height:82px;resize:vertical}.pair{display:grid;grid-template-columns:1fr 1fr;gap:8px}.composer button{width:100%;margin-top:5px}.notice{font-size:13px;margin:10px 0;color:#a13d27}.empty{background:#fff;border:1px dashed var(--line);border-radius:12px;padding:24px;color:var(--muted)}@media(max-width:800px){.layout{grid-template-columns:1fr}.hero{padding-top:38px}.composer{order:-1}}@media(max-width:480px){.wrap{padding:0 16px}.pair{grid-template-columns:1fr}.filters input{max-width:none;width:100%}}
</style></head><body><div class="wrap"><nav class="nav"><a class="brand" href="/">balkan<i>.</i>works</a><a href="/account">Moj nalog →</a></nav><header class="hero"><div><div class="eyebrow">__EYEBROW__</div><h1>__TITLE__</h1><p class="lead">__LEAD__</p></div></header><section class="filters"><input id="filter-country" value="RS" maxlength="2" placeholder="Država (RS)"><input id="filter-city" placeholder="Grad"><button id="filter">Pretraži</button></section><main class="layout"><section><div class="list" id="list"><div class="empty">Učitavamo…</div></div></section><aside class="composer"><h2>Dodaj na platformu</h2><p>Za objavu se prijavi istim Balkan.works nalogom. Firme kreiraju Deals i Save Food sadržaj samo za sopstveni profil.</p><div id="form-fields">__FORM__</div><button id="submit">__ACTION__</button><div class="notice" id="notice"></div></aside></main></div><script>
const config=__CONFIG__;const token=()=>localStorage.getItem('balkan_access_token');const escapeHtml=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));const money=(value,currency='EUR')=>value==null?'Dogovor':Number(value).toLocaleString('sr-RS',{style:'currency',currency});const dt=value=>value?new Date(value).toLocaleString('sr-RS'):'—';function authHeaders(){return token()?{authorization:'Bearer '+token()}:{};}async function request(url,options={}){const response=await fetch(url,{...options,headers:{...authHeaders(),...(options.headers||{})}});const data=await response.json().catch(()=>({}));if(!response.ok)throw new Error(data.detail||'Zahtev nije uspeo.');return data}function render(items){const list=document.querySelector('#list');if(!items.length){list.innerHTML='<div class="empty">'+config.empty+'</div>';return}list.innerHTML=items.map(item=>{if(config.kind==='market')return '<article class="item"><div class="item-top"><div><span class="pill">'+escapeHtml(item.listing_type)+'</span><h2>'+escapeHtml(item.title)+'</h2></div><div class="price">'+money(item.price,item.currency)+'</div></div><p>'+escapeHtml(item.description)+'</p><div class="meta">'+escapeHtml(item.city_name||'Balkan')+', '+escapeHtml(item.country_code)+' · objavljeno '+dt(item.created_at)+'</div></article>';if(config.kind==='deals')return '<article class="item"><div class="item-top"><div><span class="pill">AKCIJA</span><h2>'+escapeHtml(item.title)+'</h2></div><div class="price">'+money(item.price,item.currency)+(item.old_price?'<div class="old">'+money(item.old_price,item.currency)+'</div>':'')+'</div></div><p>'+escapeHtml(item.description||'')+'</p><div class="meta">'+escapeHtml(item.city_name||item.country_code)+' · važi do '+dt(item.valid_until)+'</div></article>';return '<article class="item"><div class="item-top"><div><span class="pill">SAVE FOOD</span><h2>'+escapeHtml(item.title)+'</h2></div><div class="price">'+money(item.price,item.currency)+'</div></div><p>'+escapeHtml(item.description||'')+'</p><div class="meta">Preuzimanje: '+dt(item.pickup_from)+' – '+dt(item.pickup_until)+' · još '+escapeHtml(item.quantity_available)+' paketa</div><button class="reserve" onclick="reserve(\''+item.id+'\')">Rezerviši paket</button></article>'}).join('')}async function load(){try{let url=config.endpoint;if(config.kind!=='food'){const country=document.querySelector('#filter-country').value.trim(),city=document.querySelector('#filter-city').value.trim();const params=new URLSearchParams();if(country)params.set('country_code',country);if(city)params.set('city_name',city);url+='?'+params.toString()}render(await request(url))}catch(error){document.querySelector('#list').innerHTML='<div class="empty">'+escapeHtml(error.message)+'</div>'}}async function businesses(){if(config.kind==='market'||!token())return;try{const data=await request('/api/businesses');const select=document.querySelector('#business_id');select.innerHTML='<option value="">Izaberi svoju firmu</option>'+data.map(x=>'<option value="'+x.id+'">'+escapeHtml(x.name)+'</option>').join('')}catch(_){}}function value(id){return document.querySelector('#'+id)?.value.trim()}function iso(id){const v=value(id);return v?new Date(v).toISOString():null}function payload(){if(config.kind==='market')return{listing_type:value('listing_type'),title:value('title'),description:value('description'),country_code:value('country_code').toUpperCase(),city_name:value('city_name')||null,price:value('price')?Number(value('price')):null,currency:(value('currency')||'EUR').toUpperCase()};if(config.kind==='deals'){const until=iso('valid_until');return{business_id:value('business_id'),source:'DEALS',title:value('title'),description:value('description')||null,price:Number(value('price')),old_price:value('old_price')?Number(value('old_price')):null,currency:'EUR',valid_from:new Date().toISOString(),valid_until:until,country_code:value('country_code').toUpperCase(),city_name:value('city_name')||null}}return{business_id:value('business_id'),title:value('title'),description:value('description')||null,quantity_available:Number(value('quantity_available')),pickup_from:iso('pickup_from'),pickup_until:iso('pickup_until'),price:Number(value('price')),currency:'EUR'}}document.querySelector('#filter').onclick=load;document.querySelector('#submit').onclick=async()=>{const n=document.querySelector('#notice');if(!token()){n.textContent='Prvo se prijavi preko stranice Moj nalog.';return}try{await request(config.endpoint,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify(payload())});n.style.color='#18704f';n.textContent='Sačuvano na platformi.';load()}catch(error){n.style.color='#a13d27';n.textContent=error.message}};async function reserve(id){if(!token()){location.href='/account';return}try{const result=await request('/api/food/packages/'+id+'/reserve',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({quantity:1})});alert('Paket je rezervisan. Kod za preuzimanje: '+result.pickup_code);load()}catch(error){alert(error.message)}}window.reserve=reserve;businesses();load();
</script></body></html>'''
    html = (template.replace("__CONFIG__", json.dumps({**config, "kind": kind}, ensure_ascii=False))
            .replace("__EYEBROW__", config["eyebrow"])
            .replace("__TITLE__", config["title"])
            .replace("__LEAD__", config["lead"])
            .replace("__FORM__", config["form"])
            .replace("__ACTION__", config["action"]))
    return html.replace("</head>", f"{LOCATION_ENHANCEMENT}</head>").replace("</body>", f"{LOCATION_SCRIPT}</body>")
